     6→/// 컴파일된 바이트코드
     7→#[derive(Debug, Clone)]
     8→pub struct Bytecode {
     9→    /// 명령어 바이트 스트림
    10→    pub instructions: Vec<u8>,
    11→
    12→    /// 상수 풀 (정수)
    13→    pub constants: Vec<i64>,
    14→}
    15→
    16→impl Bytecode {
    17→    /// 새로운 바이트코드 생성
    18→    pub fn new() -> Self {
    19→        Bytecode {
    20→            instructions: Vec::new(),
    21→            constants: Vec::new(),
    22→        }
    23→    }
    24→
    25→    /// 명령어 길이
    26→    pub fn len(&self) -> usize {
    27→        self.instructions.len()
    28→    }
    29→
    30→    /// 상수 추가
    31→    pub fn add_constant(&mut self, value: i64) -> usize {
    32→        self.constants.push(value);
    33→        self.constants.len() - 1
    34→    }
    35→
    36→    /// 명령어 추가
    37→    pub fn add_instruction(&mut self, instruction: u8) {
    38→        self.instructions.push(instruction);
    39→    }
    40→
    41→    /// 명령어 범위 조회
    42→    pub fn get_instructions(&self, start: usize, end: usize) -> Option<&[u8]> {
    43→        if start < end && end <= self.instructions.len() {
    44→            Some(&self.instructions[start..end])
    45→        } else {
    46→            None
    47→        }
    48→    }
    49→
    50→    /// 지정된 위치의 상수 조회
    51→    pub fn get_constant(&self, index: usize) -> Option<i64> {
    52→        self.constants.get(index).copied()
    53→    }
    54→}
    55→
    56→impl Default for Bytecode {
    57→    fn default() -> Self {
    58→        Self::new()
    59→    }
    60→}
    61→
