     2→// Compiler: AST를 바이트코드로 변환
     3→// ============================================================================
     4→
     5→use crate::ast::{Expression, Program, Statement};
     6→use crate::bytecode::Bytecode;
     7→use crate::opcode::OpCode;
     8→
     9→/// ============================================================================
    10→/// 컴파일러 - AST → 바이트코드 변환의 핵심
    11→/// ============================================================================
    12→pub struct Compiler {
    13→    bytecode: Bytecode,
    14→}
    15→
    16→impl Compiler {
    17→    /// 새로운 컴파일러 생성
    18→    pub fn new() -> Self {
    19→        Compiler {
    20→            bytecode: Bytecode::new(),
    21→        }
    22→    }
    23→
    24→    /// 프로그램 컴파일 (메인 진입점)
    25→    pub fn compile(&mut self, program: &Program) -> Result<(), String> {
    26→        for statement in &program.statements {
    27→            self.compile_statement(statement)?;
    28→        }
    29→        Ok(())
    30→    }
    31→
    32→    /// 문장 컴파일
    33→    fn compile_statement(&mut self, stmt: &Statement) -> Result<(), String> {
    34→        match stmt {
    35→            Statement::Let { name: _, value } => {
    36→                // 값을 먼저 컴파일 (변수 할당은 후위 순서로)
    37→                self.compile_expression(value)?;
    38→            }
    39→
    40→            Statement::Expression(expr) => {
    41→                self.compile_expression(expr)?;
    42→            }
    43→
    44→            Statement::Return(expr) => {
    45→                self.compile_expression(expr)?;
    46→                self.emit(OpCode::OpReturnValue);
    47→            }
    48→
    49→            Statement::Block(stmts) => {
    50→                for stmt in stmts {
    51→                    self.compile_statement(stmt)?;
    52→                }
    53→            }
    54→        }
    55→        Ok(())
    56→    }
    57→
    58→    /// ============================================================================
    59→    /// [핵심] 표현식 컴파일 - 후위 순회(Post-order)로 바이트코드 생성
    60→    /// ============================================================================
    61→    fn compile_expression(&mut self, expr: &Expression) -> Result<(), String> {
    62→        match expr {
    63→            // 정수: 상수 풀에 추가하고 OpConstant 방출
    64→            Expression::Integer(value) => {
    65→                let idx = self.bytecode.add_constant(*value);
    66→                self.emit_with_operand(OpCode::OpConstant, idx as u16);
    67→            }
    68→
    69→            // 불리언
    70→            Expression::Boolean(true) => {
    71→                self.emit(OpCode::OpTrue);
    72→            }
    73→            Expression::Boolean(false) => {
    74→                self.emit(OpCode::OpFalse);
    75→            }
    76→
    77→            // null
    78→            Expression::Null => {
    79→                self.emit(OpCode::OpNull);
    80→            }
    81→
    82→            // 전위 연산: -x, !x
    83→            Expression::Prefix(op, right) => {
    84→                // 1. 오른쪽 먼저 컴파일
    85→                self.compile_expression(right)?;
    86→                // 2. 연산자 방출
    87→                match op.as_str() {
    88→                    "-" => self.emit(OpCode::OpMinus),
    89→                    "!" => self.emit(OpCode::OpBang),
    90→                    _ => return Err(format!("Unknown prefix operator: {}", op)),
    91→                }
    92→            }
    93→
    94→            // 중위 연산: x + y, x - y 등
    95→            Expression::Infix(op, left, right) => {
    96→                // 1. 왼쪽 피연산자 컴파일 (스택에 푸시)
    97→                self.compile_expression(left)?;
    98→                // 2. 오른쪽 피연산자 컴파일 (스택에 푸시)
    99→                self.compile_expression(right)?;
   100→                // 3. 연산자 방출 (스택에서 두 값을 팝하고 결과 푸시)
   101→                match op.as_str() {
   102→                    "+" => self.emit(OpCode::OpAdd),
   103→                    "-" => self.emit(OpCode::OpSub),
   104→                    "*" => self.emit(OpCode::OpMul),
   105→                    "/" => self.emit(OpCode::OpDiv),
   106→                    "==" => self.emit(OpCode::OpEqual),
   107→                    "!=" => self.emit(OpCode::OpNotEqual),
   108→                    "<" => self.emit(OpCode::OpLessThan),
   109→                    ">=" => self.emit(OpCode::OpGreaterThanOrEqual),
   110→                    _ => return Err(format!("Unknown infix operator: {}", op)),
   111→                }
   112→            }
   113→
   114→            // if 표현식
   115→            Expression::If {
   116→                condition,
   117→                consequence,
   118→                alternative,
   119→            } => {
   120→                // 1. 조건 컴파일
   121→                self.compile_expression(condition)?;
   122→
   123→                // 2. 점프 명령어 방출 (목적지는 아직 모름)
   124→                let jump_pos = self.emit_placeholder(OpCode::OpJumpNotTruthy);
   125→
   126→                // 3. consequence 블록 컴파일
   127→                for stmt in consequence {
   128→                    self.compile_statement(stmt)?;
   129→                }
   130→
   131→                // 4. 점프 목적지 수정 (backfilling)
   132→                self.fix_jump(jump_pos);
   133→
   134→                // 5. else 블록 처리
   135→                if let Some(alt) = alternative {
   136→                    for stmt in alt {
   137→                        self.compile_statement(stmt)?;
   138→                    }
   139→                }
   140→            }
   141→
   142→            // 함수 호출
   143→            Expression::Call { function, arguments } => {
   144→                // 1. 함수 컴파일
   145→                self.compile_expression(function)?;
   146→
   147→                // 2. 인자들 컴파일
   148→                for arg in arguments {
   149→                    self.compile_expression(arg)?;
   150→                }
   151→
   152→                // 3. Call 명령어 (인자 개수 지정)
   153→                self.emit_with_operand(OpCode::OpCall, arguments.len() as u16);
   154→            }
   155→
   156→            // 배열
   157→            Expression::Array(elements) => {
   158→                // 1. 각 요소 컴파일
   159→                for elem in elements {
   160→                    self.compile_expression(elem)?;
   161→                }
   162→                // 2. Array 명령어 (요소 개수)
   163→                self.emit_with_operand(OpCode::OpArray, elements.len() as u16);
   164→            }
   165→
   166→            // 인덱싱
   167→            Expression::Index(left, index) => {
   168→                // 1. 왼쪽(배열/해시) 컴파일
   169→                self.compile_expression(left)?;
   170→                // 2. 인덱스 컴파일
   171→                self.compile_expression(index)?;
   172→                // 3. Index 명령어
   173→                self.emit(OpCode::OpIndex);
   174→            }
   175→
   176→            // 식별자 (추후 구현)
   177→            Expression::Identifier(_) => {
   178→                return Err("Identifiers not yet implemented".to_string());
   179→            }
   180→        }
   181→
   182→        Ok(())
   183→    }
   184→
   185→    /// 단일 바이트 명령어 방출
   186→    fn emit(&mut self, op: OpCode) {
   187→        self.bytecode.add_instruction(op.as_byte());
   188→    }
   189→
   190→    /// 피연산자(u16 = 2바이트)를 포함한 명령어 방출
   191→    fn emit_with_operand(&mut self, op: OpCode, operand: u16) {
   192→        self.emit(op);
   193→        // u16을 [high_byte, low_byte]로 분해
   194→        let high = (operand >> 8) as u8;
   195→        let low = (operand & 0xFF) as u8;
   196→        self.bytecode.add_instruction(high);
   197→        self.bytecode.add_instruction(low);
   198→    }
   199→
   200→    /// 점프 명령어를 방출하지만 목적지는 아직 모름 (나중에 수정)
   201→    fn emit_placeholder(&mut self, op: OpCode) -> usize {
   202→        let pos = self.bytecode.len();
   203→        self.emit(op);
   204→        self.emit_with_operand(OpCode::OpJump, 0);  // 임시 값
   205→        pos
   206→    }
   207→
   208→    /// 이전에 방출한 점프의 목적지를 수정
   209→    fn fix_jump(&mut self, pos: usize) {
   210→        let target = self.bytecode.len() as u16;
   211→        // pos+1, pos+2에 있는 jump 주소를 현재 위치로 수정
   212→        if pos + 2 < self.bytecode.instructions.len() {
   213→            let high = (target >> 8) as u8;
   214→            let low = (target & 0xFF) as u8;
   215→            self.bytecode.instructions[pos + 1] = high;
   216→            self.bytecode.instructions[pos + 2] = low;
   217→        }
   218→    }
   219→
   220→    /// 컴파일된 바이트코드 반환
   221→    pub fn bytecode(&self) -> Bytecode {
   222→        self.bytecode.clone()
   223→    }
   224→}
   225→
   226→impl Default for Compiler {
   227→    fn default() -> Self {
   228→        Self::new()
   229→    }
   230→}
   231→
   232→#[cfg(test)]
   233→mod tests {
   234→    use super::*;
   235→
   236→    #[test]
   237→    fn test_compile_integer_literal() {
   238→        let mut compiler = Compiler::new();
   239→        let program = Program::new(vec![Statement::Expression(Expression::Integer(42))]);
   240→
   241→        compiler.compile(&program).unwrap();
   242→        let bytecode = compiler.bytecode();
   243→
   244→        assert!(!bytecode.instructions.is_empty());
   245→        assert_eq!(bytecode.constants.len(), 1);
   246→        assert_eq!(bytecode.constants[0], 42);
   247→    }
   248→
   249→    #[test]
   250→    fn test_compile_boolean() {
   251→        let mut compiler = Compiler::new();
   252→        let program = Program::new(vec![
   253→            Statement::Expression(Expression::Boolean(true)),
   254→            Statement::Expression(Expression::Boolean(false)),
   255→        ]);
   256→
   257→        compiler.compile(&program).unwrap();
   258→        let bytecode = compiler.bytecode();
   259→
   260→        assert!(!bytecode.instructions.is_empty());
   261→    }
   262→
   263→    #[test]
   264→    fn test_compile_infix_expression() {
   265→        let mut compiler = Compiler::new();
   266→        let program = Program::new(vec![Statement::Expression(Expression::Infix(
   267→            "+".to_string(),
   268→            Box::new(Expression::Integer(5)),
   269→            Box::new(Expression::Integer(3)),
   270→        ))]);
   271→
   272→        compiler.compile(&program).unwrap();
   273→        let bytecode = compiler.bytecode();
   274→
   275→        // PUSH 5, PUSH 3, ADD
   276→        assert_eq!(bytecode.constants.len(), 2);
   277→        assert_eq!(bytecode.constants[0], 5);
   278→        assert_eq!(bytecode.constants[1], 3);
   279→    }
